#include<bits/stdc++.h>
using namespace std;
char s[330];
int p;
int dp[330][330];
int main()
{
    scanf("%s%d",s+1,&p);
    int n=strlen(s+1);
    for(int i=1;i<=n;i++)
    {
        dp[i][i]=1;
    }
    for(int len=2;len<=n;len++)
    {
        for(int l=1,r=len;r<=n;l++,r++)
        {
            dp[l][r]=dp[l+1][r]+1;
            if(s[l]=='o')
            {
                for(int k=l+1;k<=r;k++)
                {
                    if(s[k]=='f'&&dp[l+1][k-1]==0)
                    {
                        dp[l][r]=min(dp[l][r],max(dp[k+1][r]-p,0));
                    }
                }
            }
        }
    }
    printf("%d",dp[1][n]);
    return 0;
}
